      "path": "app/frontend/src/assets/styles.css",
      "content": "body { font-family: sans-serif; margin: 0; padding: 0; background-color: #f4f7f6; color: #333; }header { background-color: #2c3e50; color: white; padding: 1em; text-align: center; }nav ul { list-style: none; padding: 0; display: flex; justify-content: center; }nav li { margin: 0 1em; }nav a { color: white; text-decoration: none; }main { padding: 2em; text-align: center; }h1 { color: #2c3e50; }img { max-width: 100%; height: auto; margin: 1em 0; }button.primary-button { background-color: #4CAF50; color: white; border: none; padding: 10px 20px; text-align: center; text-decoration: none; display: inline-block; font-size: 16px; margin: 4px 2px; cursor: pointer; border-radius: 5px; }footer { background-color: #ddd; padding: 1em; text-align: center; position: fixed; bottom: 0; width: 100%; }"
